1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	type Damage = { itemType: string; amount: number };
15	type Incident = { cause: string; damages: Damage[] };
16	type QuoteStep = { op: "quote"; items: Item[] };
17	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
18	type Step = QuoteStep | ClaimStep;
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	type QuoteResult = { premium: number };
21	type ClaimResult = { payout: number; remainingCap: number };
22	type StepResult = QuoteResult | ClaimResult;
23	type ScenarioResult = { results: StepResult[] };
24	
25	const INSURANCE_VALUE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const DEDUCTIBLE = 100;
35	const CAP_MULTIPLIER = 2;
36	
37	const COMPONENT_BLOCK_SIZE = 3;
38	const COMPONENT_BLOCK_PREMIUM = 60;
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	
41	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
42	
43	const groupByType = (items: Item[]): Map<string, Item[]> => {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const bucket = groups.get(item.type) ?? [];
47	    bucket.push(item);
48	    groups.set(item.type, bucket);
49	  }
50	  return groups;
51	};
52	
53	const groupBasePremium = (type: string, group: Item[]): number => {
54	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
55	    return COMPONENT_BLOCK_PREMIUM;
56	  }
57	  return group.reduce((sum, item) => sum + itemBasePremium(item), 0);
58	};
59	
60	const policyBasePremium = (items: Item[]): number =>
61	  Array.from(groupByType(items).entries()).reduce(
62	    (total, [type, group]) => total + groupBasePremium(type, group),
63	    0,
64	  );
65	
66	const CURSE_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_YEARS_THRESHOLD = 2;
71	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
72	
73	type Customer = { yearsWithMHPCO: number };
74	
75	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
76	
77	const curseSurcharge = (item: Item): number =>
78	  item.cursed ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
79	
80	const highEnchantmentSurcharge = (item: Item): number =>
81	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
82	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
83	    : 0;
84	
85	const itemSurcharges = (items: Item[]): number =>
86	  items.reduce(
87	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
88	    0,
89	  );
90	
91	const quotePremium = (
92	  items: Item[],
93	  customer: Customer,
94	  isFollowUp: boolean,
95	): number => {
96	  const basePremium = policyBasePremium(items);
97	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
98	  const loyaltyDiscount =
99	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
100	      ? basePremium * LOYALTY_DISCOUNT_RATE
101	      : 0;
102	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
103	  return (
104	    basePremium +
105	    itemSurcharges(items) +
106	    firstInsuranceSurcharge -
107	    loyaltyDiscount -
108	    followUpDiscount +
109	    PROCESSING_FEE
110	  );
111	};
112	
113	const policyInsuranceSum = (items: Item[]): number =>
114	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
115	
116	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
117	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
118	
119	const reimbursableAmount = (item: Item, damageAmount: number): number =>
120	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
121	    ? damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE
122	    : damageAmount;
123	
124	const damagePayout = (items: Item[], damage: Damage): number => {
125	  const item = items.find((i) => i.type === damage.itemType)!;
126	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
127	};
128	
129	const claimPayout = (items: Item[], damages: Damage[]): number =>
130	  damages.reduce((sum, d) => sum + damagePayout(items, d), 0);
131	
132	const policyCap = (items: Item[]): number =>
133	  policyInsuranceSum(items) * CAP_MULTIPLIER;
134	
135	const countBy = <T>(xs: T[], key: (x: T) => string): Map<string, number> => {
136	  const counts = new Map<string, number>();
137	  for (const x of xs) {
138	    const k = key(x);
139	    counts.set(k, (counts.get(k) ?? 0) + 1);
140	  }
141	  return counts;
142	};
143	
144	const validateDamageCounts = (items: Item[], damages: Damage[]): void => {
145	  const insuredCounts = countBy(items, (i) => i.type);
146	  const damageCounts = countBy(damages, (d) => d.itemType);
147	  for (const [type, claimed] of damageCounts) {
148	    const insured = insuredCounts.get(type) ?? 0;
149	    if (claimed > insured) {
150	      throw new Error(`damages contain ${claimed} ${type}(s) but policy covers ${insured}`);
151	    }
152	  }
153	};
154	
155	const settleClaim = (
156	  items: Item[],
157	  incident: Incident,
158	  remainingCap: number,
159	): ClaimResult => {
160	  validateDamageCounts(items, incident.damages);
161	  const rawPayout = claimPayout(items, incident.damages);
162	  const payout = Math.min(rawPayout, remainingCap);
163	  return { payout, remainingCap: remainingCap - payout };
164	};
165	
166	const quoteForPolicy = (
167	  items: Item[],
168	  customer: Customer,
169	  isFollowUp: boolean,
170	): QuoteResult => ({
171	  premium: Math.ceil(quotePremium(items, customer, isFollowUp)),
172	});
173	
174	export const runScenario = (scenario: Scenario): ScenarioResult => {
175	  const policies: Item[][] = [];
176	  const remainingCaps: number[] = [];
177	  const results: StepResult[] = scenario.steps.map((step) => {
178	    if (step.op === "quote") {
179	      const isFollowUp = policies.length > 0;
180	      policies.push(step.items);
181	      remainingCaps.push(policyCap(step.items));
182	      return quoteForPolicy(step.items, scenario.customer, isFollowUp);
183	    }
184	    const result = settleClaim(
185	      policies[step.policy],
186	      step.incident,
187	      remainingCaps[step.policy],
188	    );
189	    remainingCaps[step.policy] = result.remainingCap;
190	    return result;
191	  });
192	  return { results };
193	};
