export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies: Item[][] = [];
  const remainingCaps: number[] = [];
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = policies.length > 0;
      policies.push(step.items);
      remainingCaps.push(policyCap(step.items));
      return quoteForPolicy(step.items, scenario.customer, isFollowUp);
    }
    const result = settleClaim(
      policies[step.policy],
      step.incident,
      remainingCaps[step.policy],
    );
    remainingCaps[step.policy] = result.remainingCap;
    return result;
  });
  return { results };
};
```

There are two parallel arrays (`policies` and `remainingCaps`) indexed by policy number. This is a Rule 3 (no duplication) concern — these two arrays form a single concept: policy state. Combining them would reveal the intent better.

